202	        items: [{ type: "amulet", cursed: true }],
203	        customerYears: 0,
204	        previousContracts: 1,
205	      }),
206	    ).toBe(92);
207	  });
208	
209	  // --- Integration: long-standing customer's second contract ---
210	  it("quote for cursed sword (steel, ench 7) for 3-yr customer's second quote returns premium 160", () => {
211	    expect(
212	      quote({
213	        items: [{ type: "sword", cursed: true, enchantment: 7 }],
214	        customerYears: 3,
215	        previousContracts: 1,
216	      }),
217	    ).toBe(160);
