230	
231	  // --- Claim: deductible per damage event ---
232	  it.todo("claim with damage to insured sword (500) and insured amulet (300) → payout 600 (deductible applies once per item)");
233	
234	  // --- Claim: enchantment threshold ---
235	  it.todo("claim on steel sword ench 9, damage 1000 → payout 400 (50% then deductible)");
236	
237	  // --- Claim: dragon material ---
238	  it.todo("claim on dragon-material sword ench 5, damage 800 → payout 700 (full reimbursement then deductible)");
239	
240	  // --- Claim: enchantment vs dragon material (50% rule wins) ---
241	  it.todo("claim on dragon-material sword ench 9, damage 1000 → payout 400 (50% rule wins, then deductible)");
242	  it.todo("claim on dragon-material sword ench 8, damage 1000 → payout 400 (high-enchantment clause applies, then deductible)");
243	
244	  // --- Claim: payout rounding ---
245	  it.todo("payout calculation yielding 350.5 rounds down to 350 (in MHPCO's favor)");
246	
247	  // --- Multiple items of the same type ---
248	  it.todo("policy covering two swords has insurance sum 2000 and cap 4000");
249	  it.todo("dragon attack damaging both swords (two sword entries) treats each as separate damage with own deductible");
250	
251	  // --- Cap ---
252	  it.todo("policy covering sword + amulet has insurance sum 1600 and cap 3200");
253	  it.todo("cap is based on unmodified insurance value: cursed sword has cap 2000 regardless of premium modifiers");
254	  it.todo("policy covering sword + 3 runes has insurance sum 1750 (block discount affects premium only, not insurance sum)");
255	
256	  // --- Cap exhaustion across successive claims ---
257	  it.todo("sword (cap 2000): first claim 1500 → payout 1400, remaining cap 600");
258	  it.todo("sword (cap 2000): second claim 1500 after first → payout 600, remaining cap 0 (reduced to remaining cap)");
259	
