3	export type Item = {
4	  type: string;
5	  material?: string;
6	  enchantment?: number;
7	  cursed?: boolean;
8	};
9	
10	export type QuoteInput = {
11	  items: Item[];
12	  customerYears: number;
13	  previousContracts: number;
14	};
15	
16	const PROCESSING_FEE = 5;
17	const COMPONENT_BLOCK_SIZE = 3;
18	const COMPONENT_BLOCK_PREMIUM = 60;
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const CURSE_SURCHARGE_RATE = 0.5;
21	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
24	const LOYALTY_DISCOUNT_RATE = 0.2;
25	const LOYALTY_YEARS_THRESHOLD = 2;
26	const FOLLOWUP_DISCOUNT_RATE = 0.15;
27	const DEDUCTIBLE = 100;
28	
29	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
30	  sword: 100,
31	  amulet: 60,
32	  staff: 80,
33	  potion: 40,
34	  rune: 25,
35	  moonstone: 25,
36	};
37	
38	function groupByType(items: Item[]): Map<string, Item[]> {
39	  const groups = new Map<string, Item[]>();
40	  for (const item of items) {
41	    const group = groups.get(item.type) ?? [];
42	    group.push(item);
43	    groups.set(item.type, group);
44	  }
45	  return groups;
46	}
47	
48	function premiumForGroup(type: string, group: Item[]): number {
49	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
50	    return COMPONENT_BLOCK_PREMIUM;
51	  }
52	  return group.length * BASE_PREMIUM_BY_TYPE[type];
53	}
54	
55	function modifierRateForItem(item: Item): number {
56	  let rate = 0;
57	  if (item.cursed) {
58	    rate += CURSE_SURCHARGE_RATE;
59	  }
60	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
61	    rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
62	  }
63	  return rate;
64	}
65	
66	function premiumForModifiedItem(item: Item): number {
67	  const base = BASE_PREMIUM_BY_TYPE[item.type];
68	  return base + base * modifierRateForItem(item);
69	}
70	
71	function hasCursedItem(items: Item[]): boolean {
72	  return items.some((item) => item.cursed);
73	}
74	
75	function hasHighEnchantmentItem(items: Item[]): boolean {
76	  return items.some(
77	    (item) => item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
78	  );
79	}
80	
81	function hasItemModifier(items: Item[]): boolean {
82	  return hasCursedItem(items) || hasHighEnchantmentItem(items);
83	}
84	
85	function baseTotalForItems(items: Item[]): number {
86	  return items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
87	}
88	
89	function premiumForItems(items: Item[]): number {
90	  if (hasItemModifier(items)) {
91	    return items.reduce((sum, item) => sum + premiumForModifiedItem(item), 0);
92	  }
93	  return Array.from(groupByType(items)).reduce(
94	    (sum, [type, group]) => sum + premiumForGroup(type, group),
95	    0,
96	  );
97	}
98	
99	function qualifiesForFirstInsuranceSurcharge(input: QuoteInput): boolean {
100	  return input.items.length === 1 && hasItemModifier(input.items);
101	}
102	
103	function qualifiesForLoyaltyDiscount(input: QuoteInput): boolean {
104	  return input.customerYears >= LOYALTY_YEARS_THRESHOLD;
105	}
106	
107	function qualifiesForFollowupDiscount(input: QuoteInput): boolean {
108	  return input.previousContracts >= 1;
109	}
110	
111	export type Damage = {
112	  itemType: string;
113	  amount: number;
114	};
115	
116	export type ClaimInput = {
117	  items: Item[];
118	  remainingCap: number;
119	  damages: Damage[];
120	};
121	
122	export type ClaimResult = {
123	  payout: number;
124	  remainingCap: number;
125	};
126	
127	export function claim(input: ClaimInput): ClaimResult {
128	  const payout = input.damages[0].amount - DEDUCTIBLE;
129	  return { payout, remainingCap: input.remainingCap };
130	}
131	
132	export function quote(input: QuoteInput): number {
133	  let premium = premiumForItems(input.items);
134	  const baseTotal = baseTotalForItems(input.items);
135	  if (qualifiesForFirstInsuranceSurcharge(input)) {
136	    premium += baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
137	  }
138	  if (qualifiesForLoyaltyDiscount(input)) {
139	    premium -= baseTotal * LOYALTY_DISCOUNT_RATE;
140	  }
141	  if (qualifiesForFollowupDiscount(input)) {
142	    premium -= baseTotal * FOLLOWUP_DISCOUNT_RATE;
143	  }
144	  return Math.ceil(premium + PROCESSING_FEE);
145	}
